import React from 'react';

const HowItWorks = () => (
    <section style={{ padding: '60px 80px', background: '#0c0a09', borderTop: '1px solid #262626' }}>
        <h2 style={{ textAlign: 'center', color: '#fef3c7', marginBottom: '50px', fontWeight: '800' }}>3 Langkah Mudah</h2>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '30px', maxWidth: '1000px', margin: '0 auto' }}>
            {['Daftar Akun', 'Cari Pekerjaan', 'Kirim Lamaran'].map((step, i) => (
                <div key={i} style={{ padding: '30px', background: '#120b06', border: '1px solid #262626', borderRadius: '16px', textAlign: 'center' }}>
                    <div style={{ width: '50px', height: '50px', background: '#ea580c', borderRadius: '50%', margin: '0 auto 20px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: '800' }}>{i + 1}</div>
                    <h3 style={{ color: '#fef3c7', marginBottom: '10px' }}>{step}</h3>
                </div>
            ))}
        </div>
    </section>
);
export default HowItWorks;
